targets.expr:
topk(
  100,
  sum by (secondld) (
    sum_over_time(
      max_over_time(
        dsc_second_ld_vs_rcode{secondld!="", secondld!~".*:.*", hostname=~"$hostname"}[$dsc_statistics_interval]
      )[$__range:$dsc_statistics_interval]
    )
  )
)

(
  (node_filesystem_size_bytes{hostname=~"$hostname", mountpoint="/", fstype!="rootfs"}
   - node_filesystem_avail_bytes{hostname=~"$hostname", mountpoint="/", fstype!="rootfs"})
  / node_filesystem_size_bytes{hostname=~"$hostname", mountpoint="/", fstype!="rootfs"}
) * 100
